 var STORAGE_KEY = "ze:last-chunk-reload";
 var MIN_INTERVAL_MS = 20000;

 var PATTERNS = [
 /Loading chunk [^\s]+ failed/i,
 /Loading CSS chunk/i,
 /ChunkLoadError/i,
 /(Failed to fetch|error loading|Importing a module script failed)[^]*dynamically imported module/i,
 /Cannot read properties of undefined \(reading 'call'\)/,
 /undefined is not an object \(evaluating '[^']*\.call'\)/,
 /can't access property "call"/
 ];

 function isRecoverable(message) {
 if (!message) return false;
 for (var i = 0; i < PATTERNS.length; i++) {
 if (PATTERNS[i].test(message)) return true;
 }
 return false;
 }

 function reloadOnce() {
 var now = Date.now();
 var last = 0;
 try { last = parseInt(window.sessionStorage.getItem(STORAGE_KEY) || "0", 10) || 0; } catch (e) {}
 if (now - last < MIN_INTERVAL_MS) return;
 try { window.sessionStorage.setItem(STORAGE_KEY, String(now)); } catch (e) {}
 window.location.reload();
 }

 window.addEventListener("error", function (event) {
 var msg = event && (event.message || (event.error && event.error.message));
 if (isRecoverable(msg)) reloadOnce();
 });

 window.addEventListener("unhandledrejection", function (event) {
 var reason = event && event.reason;
 var msg = reason && (typeof reason === "string" ? reason : reason.message);
 if (isRecoverable(msg)) reloadOnce();
 });
 } catch (e) {}
